		, @FullName
		, @PublicFullName
		, @SSN
		, @FirstName
		, @MiddleName
		, @LastName
		, @PreferredName
		, @CompanyName
		, @MaritalStatus
		, @SpouseName
		, @UserName
		, @Password
		, @BirthDate
		, @HomeTown
		, @BirthCity
		, @BirthState
		, @BirthCountry
		, @Sex
		, @ShirtSize
		, @HatSize
		, @DLNumber
		, @DLState
