		, @IsActive
		, @ModifiedById
		, @CreatedById
	 );

	 /*************
	 * Return ROW
	 **************/
	 SELECT * FROM RSU.UserResources
		WHERE
		(UserResourceID = SCOPE_IDENTITY());

END;

